abudawud_list = filter_book('سنن أبي داود')

def find_hadiths_with_terms(entries, terms):
    results = []
    for i, h in enumerate(entries):
        for field in ('Matn','hadithTxt'):
            txt = h.get(field)
            if not txt:
                continue
            n = normalize_arabic(txt)
            if all(term in n for term in terms):
                results.append((h, field, txt))
    return results

